<template>
    <div>
       <!-- 面包屑 -->
      <el-breadcrumb separator-class="el-icon-arrow-right">
         <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
         <el-breadcrumb-item>商品管理</el-breadcrumb-item>
         <el-breadcrumb-item>参数列表</el-breadcrumb-item>
       </el-breadcrumb>
       <!-- 卡片 -->
       <el-card class="box-card">
               <el-alert
               title="注意：只允许为第三级分类设置相关参数"
               type="warning"
               effect="dark">
            </el-alert>

            <div class="block">
               <span class="demonstration">选择商品分类</span>
               <!-- 连机选项 -->
               <el-cascader
                 v-model="value"
                 :options="options"
                 @change="handleChange(value)"
                 :props="{ expandTrigger: 'hover', label:'cat_name', value:'cat_id' }"
                 ></el-cascader>
             </div>

                  <!-- tabs -->
                  <div class="border-card">
                     <el-tabs type="border-card">
                        <el-tab-pane label="动态参数">
                           <el-button type="primary" size="mini" disabled>添加参数</el-button>
                        </el-tab-pane>
                        <el-tab-pane label="静态属性">
                           <el-button type="primary" size="mini" disabled>添加属性</el-button>
                        </el-tab-pane>
                     </el-tabs>
                     <!-- 表格 -->
                     <el-table
                     :data="tableData"
                     border
                     style="width: 100%">
                     <el-table-column
                       prop="date"
                       label="">
                     </el-table-column>
                     <el-table-column
                       type="index"
                       label="#"
                       >
                     </el-table-column>
                     <el-table-column
                       prop="attr_name"
                       label="属性名称"
                       width="550px">
                     </el-table-column>
                     <el-table-column
                       prop="address"
                       label="操作"
                       width="550px"
                       >
                     </el-table-column>
                   </el-table>
                  </div>


       </el-card>








    </div>
</template>

<script>
export default {
    data() {
        return {
           a:1,
           b:5,
         value: [],
        options: [],//联动数据
        tableData:[],
        tableData2:[],
         id:0,
        };
    },
    created() {

    },
    mounted() {
      this.ajax()
    },
    methods: {
      handleChange(value) {
        console.log(value);
      },
      ajax(){
         this.$http.get('/categories',{
            params:{
               pagenum: this.a,
               pagesize: this.b
            }
         }).then(res=>{
            console.log(res.data.data.result)
            this.options=res.data.data.result
         })
      },
       // 动态分类渲染获取数据
    async handleChange(i){
       console.log(111)
      if(this.id==0){
        let id = i[i.length-1]
      this.id = id
      }

      let {data:list} = await this.$http.get(`/categories/${this.id}/attributes`,{
        params:{
          sel:'many'
        }
      })
      let {data:list2} = await this.$http.get(`/categories/${this.id}/attributes`,{
        params:{
          sel:'only'
        }
      })
      this.tableData = list.data
      this.tableData2 = list2.data
      // if(this.listActive.length!=0||this.listPublic.length!=0){
        this.flag=false
      // }
      console.log(this.tableData,this.id)
    },
    }
};
</script>

<style scoped>
   .box-card{
      margin-top: 10px;
   }
   .block{
      margin-top: 10px;
   }
   .border-card{
      margin-top: 20px;
   }
</style>
